let status: string = '' // 响应码
    let content: string | Object | ArrayBuffer = '' // 响应内容
    let client: HttpClient = new HttpClient.Builder()
      .setConnectTimeout(10, TimeUnit.SECONDS)
      .setReadTimeout(10, TimeUnit.SECONDS)
      .setWriteTimeout(10, TimeUnit.SECONDS)
      .build();
    let request: Request = new Request.Builder()
      .get("https://postman-echo.com/get?foo1=bar1&foo2=bar2")
      .addHeader("Content-Type", "application/json")
      .params("testKey1","testValue1")
      .build();
    // 发起请求
    client.newCall(request).enqueue((result: Response) => {
      if (result) {
        status = result.responseCode.toString();
      }
      if (result.result) {
        content = result.result;
      } else {
        content = JSON.stringify(result);
      }
      Logger.info("onComplete -> Status : " + status);
      Logger.info("onComplete -> Content : " + JSON.stringify(content));
    }, (error: ESObject) => {
      status = error.code.toString();
      content = error.data;
      Logger.info("onError -> Error : " + content);
    });

