//网络请求方法：
async getData(append: boolean) {
    setTimeout(() => {
      if (!append) {
        this.page = 1;
      }
      let array: number[] = [];
      let startIndex = (this.page - 1) * 10;
      let endIndex = this.page * 10;
      for (let index = startIndex; index < endIndex; index++) {
        array.push(index);
      }

      if(append){
        this.dataArray.push(...array);
      }else {
        this.dataArray = [];
        this.dataArray = array;
      }
      this.page ++;
    }, 500)
  }

