Button('点击显示弹窗').onClick(()=>{
let controller = new UIAlertView('弹窗提示', '这是一个系统弹窗，仿iOS风格是吗', UIAlertControllerStyle.Alert, this);
  let confirmAction = new UIAlertAction('确定', UIAlertActionStyle.Destructive, (action) => {
    controller.close();
  });
  let okAction = new UIAlertAction('知道了', UIAlertActionStyle.Default, (action) => {
    controller.close();
  });
  let cancelAction = new UIAlertAction('取消', UIAlertActionStyle.Cancel, (action) => {
    controller.close();
  })
  controller.addAction(confirmAction);
  // controller.addAction(okAction);
  controller.addAction(cancelAction);
  controller.show();
})

